const _mq=()=>matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light";const _sw=()=>document.querySelector("#light-dark-switch");function getPreferredColorScheme(){const sys=_mq(),stored=localStorage.getItem("scheme"),r=stored||sys;if(sys===r){localStorage.removeItem("scheme")}return r}function savePreferredColorScheme(e){_mq()===e?localStorage.removeItem("scheme"):localStorage.setItem("scheme",e)}function toggleColorScheme(){const e=getPreferredColorScheme()==="light"?"dark":"light";applyPreferredColorScheme(e);savePreferredColorScheme(e)}function applyPreferredColorScheme(e){const sw=_sw();for(const ss of Array.from(document.styleSheets)){let rules;try{rules=ss.cssRules}catch{continue};for(const rule of Array.from(rules)){if(!rule?.media?.mediaText.includes("prefers-color-scheme")){continue}const m=rule.media;if(e==="light"){m.appendMedium("original-prefers-color-scheme");if(m.mediaText.includes("light")){m.deleteMedium("(prefers-color-scheme: light)")}if(m.mediaText.includes("dark")){m.deleteMedium("(prefers-color-scheme: dark)")}sw.checked=false}else if(e==="dark"){m.appendMedium("(prefers-color-scheme: light)");m.appendMedium("(prefers-color-scheme: dark)");if(m.mediaText.includes("original")){m.deleteMedium("original-prefers-color-scheme")}sw.checked=true}else{m.appendMedium("(prefers-color-scheme: dark)");if(m.mediaText.includes("light")){m.deleteMedium("(prefers-color-scheme: light)")}if(m.mediaText.includes("original")){m.deleteMedium("original-prefers-color-scheme")}sw.checked=m.mediaText.includes("light")}}}}applyPreferredColorScheme(getPreferredColorScheme());
